use distributed_inference::math::*;
use distributed_inference::model_phi3::*;
use std::time::Instant;

// Phi-3-mini dimensions
const PHI3_HIDDEN: usize = 3072;
const PHI3_INTERMEDIATE: usize = 8192;
const PHI3_LAYERS: usize = 32;
const ITERATIONS: usize = 50;

fn deterministic_input(dim: usize) -> Vec<f32> {
    (0..dim).map(|i| ((i as f32) * 0.1).sin()).collect()
}

fn deterministic_weights(rows: usize, cols: usize) -> Vec<f32> {
    (0..rows * cols)
        .map(|i| {
            let val = (i as f32 * 0.0625).sin();
            val / (cols as f32).sqrt()
        })
        .collect()
}

/// Test 1: Standard SwiGLU - baseline
fn bench_swiglu_standard() -> (f64, usize) {
    let x = deterministic_input(PHI3_HIDDEN);
    let gate_w = deterministic_weights(PHI3_INTERMEDIATE, PHI3_HIDDEN);
    let up_w = deterministic_weights(PHI3_INTERMEDIATE, PHI3_HIDDEN);
    let down_w = deterministic_weights(PHI3_HIDDEN, PHI3_INTERMEDIATE);

    let mut out = vec![0.0; PHI3_HIDDEN];
    let mut gate_scratch = vec![0.0; PHI3_INTERMEDIATE];
    let mut up_scratch = vec![0.0; PHI3_INTERMEDIATE];

    let start = Instant::now();
    for _ in 0..ITERATIONS {
        phi3_swiglu_ffn_f32(
            &mut out,
            &x,
            &gate_w,
            &up_w,
            &down_w,
            &mut gate_scratch,
            &mut up_scratch,
            PHI3_HIDDEN,
            PHI3_INTERMEDIATE,
        );
    }
    let elapsed = start.elapsed();
    let ops = 2 * PHI3_INTERMEDIATE * PHI3_HIDDEN + PHI3_HIDDEN * PHI3_INTERMEDIATE;
    (elapsed.as_secs_f64() / ITERATIONS as f64, ops)
}

/// Test 2: Fused gate+up (single matmul instead of two)
fn bench_swiglu_fused_gate_up() -> (f64, usize) {
    let x = deterministic_input(PHI3_HIDDEN);
    // Fused gate+up has double the width
    let gate_up_w = deterministic_weights(2 * PHI3_INTERMEDIATE, PHI3_HIDDEN);
    let down_w = deterministic_weights(PHI3_HIDDEN, PHI3_INTERMEDIATE);

    let mut out = vec![0.0; PHI3_HIDDEN];
    let mut gate_up_scratch = vec![0.0; 2 * PHI3_INTERMEDIATE];

    let start = Instant::now();
    for _ in 0..ITERATIONS {
        // Single fused matmul: x @ gate_up_w.T
        mat_vec_f32(
            &mut gate_up_scratch,
            &x,
            &gate_up_w,
            2 * PHI3_INTERMEDIATE,
            PHI3_HIDDEN,
        );

        // Split and apply gate activation on first half
        let (gate_part, up_part) = gate_up_scratch.split_at_mut(PHI3_INTERMEDIATE);
        for i in 0..PHI3_INTERMEDIATE {
            gate_part[i] = silu(gate_part[i]) * up_part[i];
        }

        // Down projection
        mat_vec_f32(&mut out, gate_part, &down_w, PHI3_HIDDEN, PHI3_INTERMEDIATE);
    }
    let elapsed = start.elapsed();
    let ops = 2 * PHI3_INTERMEDIATE * PHI3_HIDDEN + PHI3_HIDDEN * PHI3_INTERMEDIATE;
    (elapsed.as_secs_f64() / ITERATIONS as f64, ops)
}

/// Test 3: Fused gate+up+down (two matmuls instead of three)
/// Uses intermediate as temp buffer
fn bench_swiglu_fused_all() -> (f64, usize) {
    let x = deterministic_input(PHI3_HIDDEN);
    let gate_up_w = deterministic_weights(2 * PHI3_INTERMEDIATE, PHI3_HIDDEN);
    let down_w = deterministic_weights(PHI3_HIDDEN, PHI3_INTERMEDIATE);

    let mut out = vec![0.0; PHI3_HIDDEN];
    let mut scratch = vec![0.0; 2 * PHI3_INTERMEDIATE];

    let start = Instant::now();
    for _ in 0..ITERATIONS {
        // Fused gate+up
        mat_vec_f32(
            &mut scratch,
            &x,
            &gate_up_w,
            2 * PHI3_INTERMEDIATE,
            PHI3_HIDDEN,
        );
        let (gate, up) = scratch.split_at_mut(PHI3_INTERMEDIATE);
        for i in 0..PHI3_INTERMEDIATE {
            gate[i] = silu(gate[i]) * up[i];
        }

        // Down
        mat_vec_f32(&mut out, gate, &down_w, PHI3_HIDDEN, PHI3_INTERMEDIATE);
    }
    let elapsed = start.elapsed();
    let ops = 2 * PHI3_INTERMEDIATE * PHI3_HIDDEN + PHI3_HIDDEN * PHI3_INTERMEDIATE;
    (elapsed.as_secs_f64() / ITERATIONS as f64, ops)
}

/// Test 4: Low-rank approximation of intermediate layer
/// Instead of 8192, use 4096 (50% reduction)
fn bench_swiglu_lowrank() -> (f64, usize) {
    let reduced_intermediate = PHI3_INTERMEDIATE / 2;
    let x = deterministic_input(PHI3_HIDDEN);
    let gate_w = deterministic_weights(reduced_intermediate, PHI3_HIDDEN);
    let up_w = deterministic_weights(reduced_intermediate, PHI3_HIDDEN);
    let down_w = deterministic_weights(PHI3_HIDDEN, reduced_intermediate);

    let mut out = vec![0.0; PHI3_HIDDEN];
    let mut gate_scratch = vec![0.0; reduced_intermediate];
    let mut up_scratch = vec![0.0; reduced_intermediate];

    let start = Instant::now();
    for _ in 0..ITERATIONS {
        phi3_swiglu_ffn_f32(
            &mut out,
            &x,
            &gate_w,
            &up_w,
            &down_w,
            &mut gate_scratch,
            &mut up_scratch,
            PHI3_HIDDEN,
            reduced_intermediate,
        );
    }
    let elapsed = start.elapsed();
    let ops = 2 * reduced_intermediate * PHI3_HIDDEN + PHI3_HIDDEN * reduced_intermediate;
    (elapsed.as_secs_f64() / ITERATIONS as f64, ops)
}

fn silu(x: f32) -> f32 {
    x / (1.0 + (-x).exp())
}

fn main() {
    println!("╔════════════════════════════════════════════════════════════════╗");
    println!("║           SwiGLU FFN OPTIMIZATION SHOOTOUT                     ║");
    println!(
        "║         Phi-3-mini: hidden={}, intermediate={}                   ║",
        PHI3_HIDDEN, PHI3_INTERMEDIATE
    );
    println!(
        "║           {} iterations, {} layers total                         ║",
        ITERATIONS, PHI3_LAYERS
    );
    println!("╚════════════════════════════════════════════════════════════════╝\n");

    let (baseline_t, baseline_ops) = bench_swiglu_standard();
    let baseline_gflops = (baseline_ops as f64 / 1e9) / baseline_t;

    println!("BASELINE: Standard 3-matmul SwiGLU");
    println!("  Time per layer/token:  {:.6} ms", baseline_t * 1000.0);
    println!(
        "  Ops:                   {} (FLOP equivalent)",
        baseline_ops
    );
    println!("  Throughput:            {:.2} GFLOP/s", baseline_gflops);
    println!(
        "  For {} layers:          {:.3} ms total",
        PHI3_LAYERS,
        baseline_t * 1000.0 * PHI3_LAYERS as f64
    );
    println!();

    let (fused_gate_up_t, fused_ops) = bench_swiglu_fused_gate_up();
    let speedup_1 = baseline_t / fused_gate_up_t;
    let gflops_1 = (fused_ops as f64 / 1e9) / fused_gate_up_t;
    println!("OPT 1: Fused gate+up (2 matmuls instead of 3)");
    println!(
        "  Time per layer/token:  {:.6} ms",
        fused_gate_up_t * 1000.0
    );
    println!("  Speedup vs baseline:   {:.2}x", speedup_1);
    println!("  Throughput:            {:.2} GFLOP/s", gflops_1);
    println!(
        "  For {} layers:          {:.3} ms total",
        PHI3_LAYERS,
        fused_gate_up_t * 1000.0 * PHI3_LAYERS as f64
    );
    println!();

    let (fused_all_t, _) = bench_swiglu_fused_all();
    let speedup_2 = baseline_t / fused_all_t;
    println!("OPT 2: Full fusion (combined gate+up+down)");
    println!("  Time per layer/token:  {:.6} ms", fused_all_t * 1000.0);
    println!("  Speedup vs baseline:   {:.2}x", speedup_2);
    println!(
        "  For {} layers:          {:.3} ms total",
        PHI3_LAYERS,
        fused_all_t * 1000.0 * PHI3_LAYERS as f64
    );
    println!();

    let (lowrank_t, lowrank_ops) = bench_swiglu_lowrank();
    let speedup_3 = baseline_t / lowrank_t;
    let gflops_3 = (lowrank_ops as f64 / 1e9) / lowrank_t;
    println!("OPT 3: 50% Low-rank (8192 → 4096 intermediate)");
    println!("  Time per layer/token:  {:.6} ms", lowrank_t * 1000.0);
    println!("  Speedup vs baseline:   {:.2}x", speedup_3);
    println!("  Throughput:            {:.2} GFLOP/s", gflops_3);
    println!(
        "  For {} layers:          {:.3} ms total",
        PHI3_LAYERS,
        lowrank_t * 1000.0 * PHI3_LAYERS as f64
    );
    println!();

    println!("╔════════════════════════════════════════════════════════════════╗");
    println!("║                         WINNER ANALYSIS                        ║");
    println!("╠════════════════════════════════════════════════════════════════╣");
    if speedup_3 > speedup_2 && speedup_3 > speedup_1 {
        println!("║  🏆 OPT 3 (Low-rank) WINS at {:.2}x speedup", speedup_3);
        println!("║  - Requires model retraining or distillation");
        println!("║  - Permanent capacity reduction (may hurt final accuracy)");
    } else if speedup_2 > speedup_1 {
        println!(
            "║  🏆 OPT 2 (Full fusion) WINS at {:.2}x speedup",
            speedup_2
        );
        println!("║  - Zero accuracy cost (mathematical identity)");
        println!("║  - Requires compiler/kernel work");
    } else {
        println!(
            "║  🏆 OPT 1 (Fused gate+up) WINS at {:.2}x speedup",
            speedup_1
        );
        println!("║  - Easy to implement (single matmul fusion)");
        println!("║  - Good win/effort ratio");
    }
    println!("╠════════════════════════════════════════════════════════════════╣");
    println!("║  NEXT STEPS:                                                   ║");
    println!("║  1. Profile actual Phi-3 model to measure saturation rates     ║");
    println!("║  2. Decide: fusion vs pruning vs low-rank vs sparsity          ║");
    println!("║  3. Implement winner + measure end-to-end latency              ║");
    println!("║  4. Benchmark against quantized (Q4K) baseline                 ║");
    println!("╚════════════════════════════════════════════════════════════════╝");
}
